"use client";
import { useQuery } from "@tanstack/react-query";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { apiUrl } from "@/lib/config";
import { fetcher } from "@/lib/api/fetcher";

// Deprecated: pipelines endpoint (retained temporarily for reference)
// export interface BatchPipeline { ... }

export interface BatchListItem {
  id: string;
  batch_name: string;
  pipeline_name: string;
  status: string;
  task_id_processing?: string | null;
  archive_url: string | null;
  archive_filename: string | null;
  total_rows: number;
  successful_rows: number;
  failed_rows: number;
  created_at: string;
  started_at: string | null;
  scheduled_at: string | null;
  completed_at: string | null;
  updated_at: string;
  notes: string | null;
}

export interface BatchListResponse {
  items: BatchListItem[];
  page: number;
  page_size: number;
  total: number;
  total_pages: number;
  error?: string;
}

async function fetchBatchList(page: number, pageSize: number): Promise<BatchListResponse> {
  const url = `/api/batch/list?page_size=${pageSize}&page=${page}`;
  const res = await fetcher(url, { cache: "no-store" });
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `Failed to load batch list (${res.status})`);
  }
  return (await res.json()) as BatchListResponse;
}

export function useBatchList(page: number, pageSize: number) {
  return useQuery({
    queryKey: ["batch", "list", page, pageSize],
    queryFn: () => fetchBatchList(page, pageSize),
    placeholderData: (prevData) => prevData,
  });
}

// Pipelines API
export interface PipelineItem {
  name: string;
  type: string; // e.g. "production" | "experimental" | other future tags
}

export interface PipelinesResponse {
  pipelines: PipelineItem[];
}

async function fetchPipelines(): Promise<PipelinesResponse> {
  const res = await fetcher(`/api/batch/pipelines`, { cache: "no-store" });
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `Failed to load pipelines (${res.status})`);
  }
  return (await res.json()) as PipelinesResponse;
}

export function usePipelines() {
  return useQuery({
    queryKey: ["batch", "pipelines"],
    queryFn: fetchPipelines,
  });
}

// Service account email
interface ServiceAccountEmailResponse {
  email: string;
}

export function useServiceAccountEmail(enabled: boolean) {
  return useQuery({
    queryKey: ["batch", "service-account-email"],
    queryFn: async () => {
      const res = await fetcher("/api/batch/service-account-email", { cache: "no-store" });
      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        throw new Error(body.error || `Failed to fetch service account email (${res.status})`);
      }
      return (await res.json()) as ServiceAccountEmailResponse;
    },
    enabled,
    staleTime: Infinity,
  });
}

// Drive Preview types
export interface DriveFileInfo {
  id: string;
  name: string;
  path: string;
  mimeType: string;
  thumbnailLink?: string;
}

export interface FileRef {
  row: number;
  directory: string;
  column: string;
  filename: string | null;
  reason?: string;
}

export interface DrivePreviewResponse {
  csv_file: { id: string; name: string };
  total_rows: number;
  image_files_in_drive: DriveFileInfo[];
  found_files: FileRef[];
  missing_files: FileRef[];
  summary: { found: number; missing: number };
}

// Drive Preview mutation
interface DrivePreviewPayload {
  drive_link: string;
  pipeline_name: string;
  accessToken: string;
}

export function useDrivePreview() {
  return useMutation({
    mutationKey: ["batch", "drive-preview"],
    mutationFn: async (payload: DrivePreviewPayload) => {
      if (!payload.accessToken) throw new Error("Missing access token");
      const res = await fetcher("/api/batch/drive-preview", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          drive_link: payload.drive_link,
          pipeline_name: payload.pipeline_name,
        }),
      });
      if (!res.ok) {
        let body: any = {};
        try {
          body = await res.json();
        } catch {}
        throw new Error(
          body?.detail?.error || body?.error || `Failed to preview Drive folder (${res.status})`,
        );
      }
      return (await res.json()) as DrivePreviewResponse;
    },
  });
}

// Create batch mutation
interface CreateBatchPayload {
  batch_name: string;
  pipeline_name: string;
  csv_file?: File;
  images_zip_file?: File;
  drive_link?: string;
  accessToken: string;
  scheduled_at?: Date;
  workflow_job_id?: string;
}

// Shape of backend validation detail for missing image files
export type BatchPromptImageIssue = {
  row?: number;
  directory?: string;
  prompt_column?: string;
  image_column?: string;
};

export type NormalizedValidationError = {
  message: string;
  count: number;
  itemLabel: string;
  items: string[];
};

export interface BatchCreateValidationDetail {
  error?: string; // summary message e.g. "Missing referenced image files"
  count?: number; // number of missing files
  files?: string[]; // list of missing file paths
  issues?: BatchPromptImageIssue[]; // prompt/image-column pairing issues
}

export interface BatchCreateError extends Error {
  status: number;
  detail?: BatchCreateValidationDetail;
}

export function useCreateBatch() {
  const qc = useQueryClient();
  return useMutation({
    mutationKey: ["batch", "create", "direct"],
    mutationFn: async (payload: CreateBatchPayload) => {
      if (!payload.accessToken) throw new Error("Missing access token");
      const formData = new FormData();
      formData.append("batch_name", payload.batch_name);
      formData.append("pipeline_name", payload.pipeline_name);
      if (payload.drive_link) {
        formData.append("drive_link", payload.drive_link);
      } else {
        formData.append("csv_file", payload.csv_file!);
        formData.append("images_zip_file", payload.images_zip_file!);
      }
      if (payload.scheduled_at) {
        formData.append("scheduled_at", payload.scheduled_at.toISOString());
      }
      if (payload.workflow_job_id) {
        formData.append("workflow_job_id", payload.workflow_job_id);
      }

      // Direct call to backend (single hop). Intentionally omit Content-Type so browser sets boundary.
      const res = await fetcher(apiUrl("/batch/create"), {
        method: "POST",
        headers: {
          Authorization: `Bearer ${payload.accessToken}`,
        },
        body: formData,
      });
      if (!res.ok) {
        let body: any = {};
        try {
          body = await res.json();
        } catch {}
        const err: BatchCreateError = Object.assign(
          new Error(body?.detail?.error || body?.error || `Failed to create batch (${res.status})`),
          { status: res.status },
        );
        if (body.detail && typeof body.detail === "object") {
          err.detail = {
            error: body.detail.error,
            count: body.detail.count,
            files: Array.isArray(body.detail.files) ? body.detail.files : undefined,
            issues: Array.isArray(body.detail.issues) ? body.detail.issues : undefined,
          };
        }
        throw err;
      }
      return res.json();
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["batch", "list"] });
    },
  });
}

// Batch Run Status API

export interface OutputUrl {
  url: string;
}

export interface RowResult {
  id: string;
  row_index: number;
  directory_name?: string | null;
  status: string;
  output_urls: OutputUrl[];
  row_archive_url: string | null;
  error_message?: string | null;
  created_at: string;
}

export interface BatchRunStatusData {
  batch_run_id: string;
  status: string; // PENDING | SUCCESS | FAILURE | QUEUED | PROCESSING
  result: unknown | null;
  error: unknown | null;
  timestamp: string | null;
  // Metadata passed through from the detail endpoint
  batch_name?: string;
  pipeline_name?: string;
  total_rows?: number;
  successful_rows?: number;
  failed_rows?: number;
  archive_url?: string | null;
  archive_filename?: string | null;
  created_at?: string;
  completed_at?: string | null;
  row_results: RowResult[];
}

async function fetchBatchRunStatus(batchRunId: string): Promise<BatchRunStatusData> {
  const res = await fetcher(`/api/batch/${batchRunId}`, { cache: "no-store" });
  if (!res.ok) {
    let body: any = {};
    try {
      body = await res.json();
    } catch {}
    throw new Error(body.error || `Failed to fetch batch run ${batchRunId} (${res.status})`);
  }
  return (await res.json()) as BatchRunStatusData;
}

export function useBatchRunStatus(batchRunId: string | null) {
  return useQuery({
    queryKey: ["batch", "status", batchRunId],
    queryFn: () => fetchBatchRunStatus(batchRunId!),
    enabled: !!batchRunId,
    refetchInterval: (query) => {
      const d = query.state.data as BatchRunStatusData | undefined;
      // Continue polling if status is processing, queued, or pending
      // Stop if success, failed, failure, completed
      const status = d?.status?.toLowerCase();
      const isTerminal =
        status === "success" ||
        status === "failed" ||
        status === "failure" ||
        status === "completed";

      return d && isTerminal ? false : 20000;
    },
  });
}

// Retry batch mutation
interface RetryBatchArgs {
  batchRunId: string;
  accessToken: string;
  workflow_job_id?: string;
}

export function useRetryBatch() {
  const client = useQueryClient();
  return useMutation({
    mutationKey: ["batch", "retry"],
    mutationFn: async (args: RetryBatchArgs) => {
      if (!args.accessToken) throw new Error("Missing access token");
      const body: Record<string, unknown> = {};
      if (args.workflow_job_id) {
        body.workflow_job_id = args.workflow_job_id;
      }
      const response = await fetcher(apiUrl(`/batch/${args.batchRunId}/retry`), {
        method: "POST",
        headers: {
          Authorization: `Bearer ${args.accessToken}`,
          "Content-Type": "application/json",
        },
        body: Object.keys(body).length > 0 ? JSON.stringify(body) : undefined,
      });
      if (!response.ok) {
        const errBody = await response.json().catch(() => ({}));
        throw new Error(errBody.error || `Failed to retry batch (${response.status})`);
      }
      return response.json();
    },
    onSuccess: () => {
      client.invalidateQueries({ queryKey: ["batch", "list"] });
    },
  });
}

// Jobs API
export interface Job {
  id: string;
  name: string;
  external_job_id: string | null;
}

// Helper function to format job display with truncated external_job_id and name
export function formatJobDisplay(job: Job): { displayId: string; displayName: string } {
  const externalId = job.external_job_id || job.id;
  const displayId = externalId.length > 10 ? externalId.slice(0, 10) + "..." : externalId;
  const displayName = job.name.length > 30 ? job.name.slice(0, 30) + "..." : job.name;
  return { displayId, displayName };
}

export interface JobsResponse {
  jobs: Job[];
}

async function fetchJobs(): Promise<JobsResponse> {
  const url = `/api/jobs`;
  const res = await fetcher(url, { cache: "no-store" });
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `Failed to load jobs (${res.status})`);
  }
  return (await res.json()) as JobsResponse;
}

export function useJobs(_userId?: string | undefined) {
  return useQuery({
    queryKey: ["jobs"],
    queryFn: () => fetchJobs(),
  });
}

